@file:Suppress("ktlint:standard:max-line-length") // base64 sprite literals must stay on one line

package warlockfe.warlock3.compose.components

import warlockfe.warlock3.compose.model.SkinImage
import warlockfe.warlock3.compose.model.SkinObject

// Sprite sheets (base64 PNG) copied from the bundled default skin, embedded so the @Preview
// composables can render the compass synchronously without loading the build-generated
// skin.zip resource (which is unavailable to the preview renderer).
private const val COMPASS_ALL_OFF = ""
private const val COMPASS_CARDINAL = ""
private const val NON_CARDINAL = ""
private const val COMPASS_UP_DOWN_GLOW = ""

private fun spriteChild(data: String) = SkinObject(image = SkinImage(data = data))

private fun direction(
    sprite: String,
    left: Int,
    top: Int,
    width: Int,
    height: Int,
) = SkinObject(sprite = sprite, left = left, top = top, width = width, height = height)

/** A self-contained compass skin for previews, using the default skin's sprites. */
internal fun previewCompassSkin(): Map<String, SkinObject> =
    mapOf(
        "compass" to
            SkinObject(
                children =
                    mapOf(
                        "background" to spriteChild(COMPASS_ALL_OFF),
                        "cardinal" to spriteChild(COMPASS_CARDINAL),
                        "nonCardinal" to spriteChild(NON_CARDINAL),
                        "upDown" to spriteChild(COMPASS_UP_DOWN_GLOW),
                        "north" to direction("cardinal", 34, 1, 14, 15),
                        "east" to direction("cardinal", 49, 14, 17, 17),
                        "south" to direction("cardinal", 32, 33, 18, 16),
                        "west" to direction("cardinal", 10, 16, 24, 19),
                        "out" to direction("cardinal", 32, 15, 18, 18),
                        "northeast" to direction("nonCardinal", 44, 6, 16, 17),
                        "northwest" to direction("nonCardinal", 24, 7, 17, 17),
                        "southwest" to direction("nonCardinal", 23, 28, 18, 15),
                        "southeast" to direction("nonCardinal", 42, 28, 19, 14),
                        "up" to direction("upDown", 0, 0, 40, 49),
                        "down" to direction("upDown", 52, 0, 29, 49),
                    ),
            ),
    )
